// Process extracted file content from backend — outputs one item per chunk
const webhook = $('Webhook').first().json.body;
const backendResponse = $input.first().json;

// Backend returns: { success, file_name, extracted_text, chunks, chunk_count, char_count }
const chunks = backendResponse.chunks || [];
const fileName = webhook.file_name || backendResponse.file_name || 'uploaded_file';
const fileUrl = webhook.file_url || null;

if (!chunks.length) {
  // Fallback: use extracted_text as single chunk
  const extractedText = backendResponse.extracted_text || '';
  if (!extractedText.trim()) {
    throw new Error(`No text could be extracted from file: ${fileName}`);
  }
  return {
    json: {
      user_id: webhook.user_id,
      agent_id: webhook.agent_id,
      category: webhook.category || 'documents',
      document: `File: ${fileName}\n\n${extractedText}`,
      source: 'file_upload',
      file_name: fileName,
      file_url: fileUrl,
      chunk_index: 0,
      total_chunks: 1
    }
  };
}

// Return one item per chunk — n8n will process each through subsequent nodes
return chunks.map((chunk, index) => ({
  json: {
    user_id: webhook.user_id,
    agent_id: webhook.agent_id,
    category: webhook.category || 'documents',
    document: `File: ${fileName} [Part ${index + 1}/${chunks.length}]\n\n${chunk}`,
    source: 'file_upload',
    file_name: fileName,
    file_url: fileUrl,
    chunk_index: index,
    total_chunks: chunks.length
  }
}));

// Process text content — chunk if too large for embedding
const webhook = $('Webhook').first().json.body;
const fullText = webhook.content || '';

if (!fullText.trim()) {
  throw new Error('No text content provided');
}

const CHUNK_SIZE = 1500;
const CHUNK_OVERLAP = 200;

// If text fits in one chunk, return directly
if (fullText.length <= CHUNK_SIZE) {
  return {
    json: {
      user_id: webhook.user_id,
      agent_id: webhook.agent_id,
      category: webhook.category || 'custom_instructions',
      document: fullText,
      source: 'agent_settings',
      chunk_index: 0,
      total_chunks: 1
    }
  };
}

// Chunk the text
const chunks = [];
let start = 0;

while (start < fullText.length) {
  let end = start + CHUNK_SIZE;

  if (end >= fullText.length) {
    const chunk = fullText.slice(start).trim();
    if (chunk) chunks.push(chunk);
    break;
  }

  const segment = fullText.slice(start, end);
  let breakPos = segment.lastIndexOf('\n\n');
  if (breakPos === -1 || breakPos < CHUNK_SIZE * 0.3) breakPos = segment.lastIndexOf('\n');
  if (breakPos === -1 || breakPos < CHUNK_SIZE * 0.3) {
    // Find last sentence end
    const sentenceMatch = segment.match(/.*[.!?]\s/s);
    if (sentenceMatch) breakPos = sentenceMatch[0].length;
  }
  if (breakPos === -1 || breakPos < CHUNK_SIZE * 0.3) breakPos = segment.lastIndexOf(' ');
  if (breakPos === -1 || breakPos < CHUNK_SIZE * 0.3) breakPos = CHUNK_SIZE;

  const chunk = fullText.slice(start, start + breakPos).trim();
  if (chunk) chunks.push(chunk);
  start = start + breakPos - CHUNK_OVERLAP;
  if (start < 0) start = 0;
}

return chunks.map((chunk, index) => ({
  json: {
    user_id: webhook.user_id,
    agent_id: webhook.agent_id,
    category: webhook.category || 'custom_instructions',
    document: chunk,
    source: 'agent_settings',
    chunk_index: index,
    total_chunks: chunks.length
  }
}));

// Collect all inserted chunk IDs and return final response
const allItems = $input.all();
const insertedIds = allItems.map(item => item.json?.id || null).filter(Boolean);

// Get metadata from Merge Paths (first item)
const trigger = $('Merge Paths').first().json;

return {
  json: {
    success: true,
    action: 'knowledge_saved',
    user_id: trigger.user_id,
    agent_id: trigger.agent_id,
    category: trigger.category,
    source: trigger.source,
    chunks_inserted: insertedIds.length,
    inserted_ids: insertedIds,
    timestamp: new Date().toISOString()
  }
};
